import{_ as a,c as s,o as e,a1 as r}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Первый запуск: Каталог данных | Antigravity Tools","description":"Изучите расположение каталога данных и управление журналами Antigravity Tools. Научитесь открывать каталог данных, очищать журналы, запускать в трее и настраивать автозапуск.","frontmatter":{"title":"Первый запуск: Каталог данных | Antigravity Tools","sidebarTitle":"Найти каталог данных","subtitle":"Первый запуск: Каталог данных, журналы, трей и автозапуск","description":"Изучите расположение каталога данных и управление журналами Antigravity Tools. Научитесь открывать каталог данных, очищать журналы, запускать в трее и настраивать автозапуск.","tags":["Первый запуск","Каталог данных","Журналы","Трей","Автозапуск"],"prerequisite":["start-getting-started","start-installation"],"order":3},"headers":[],"relativePath":"ru/lbjlaq/Antigravity-Manager/start/first-run-data/index.md","filePath":"ru/lbjlaq/Antigravity-Manager/start/first-run-data/index.md"}'),i={name:"ru/lbjlaq/Antigravity-Manager/start/first-run-data/index.md"};function d(o,t,l,n,c,h){return e(),s("div",null,[...t[0]||(t[0]=[r(`<h1 id="первыи-запуск-каталог-данных-журналы-треи-и-автозапуск" tabindex="-1">Первый запуск: Каталог данных, журналы, трей и автозапуск <a class="header-anchor" href="#первыи-запуск-каталог-данных-журналы-треи-и-автозапуск" aria-label="Permalink to &quot;Первый запуск: Каталог данных, журналы, трей и автозапуск&quot;">​</a></h1><p>Многие возможности Antigravity Tools, которые кажутся «магическими» (пул аккаунтов, квоты, мониторинг, статистика, фоновая работа), в итоге сводятся к двум вещам: <strong>каталог данных</strong> и <strong>журналы</strong>. Если разобраться с этими двумя компонентами при первом запуске, это сэкономит много времени при устранении неполадок в будущем.</p><h2 id="что-такое-каталог-данных" tabindex="-1">Что такое каталог данных? <a class="header-anchor" href="#что-такое-каталог-данных" aria-label="Permalink to &quot;Что такое каталог данных?&quot;">​</a></h2><p><strong>Каталог данных</strong> — это папка на вашем компьютере, где Antigravity Tools сохраняет своё состояние: JSON-файлы аккаунтов, файлы квот, файлы журналов, а также базы данных SQLite для Token Stats и Proxy Monitor. При создании резервных копий/миграции/устранении неполадок достаточно определить этот каталог, чтобы найти авторитетный источник данных.</p><h2 id="чему-вы-научитесь" tabindex="-1">Чему вы научитесь <a class="header-anchor" href="#чему-вы-научитесь" aria-label="Permalink to &quot;Чему вы научитесь&quot;">​</a></h2><ul><li>Знать, где находится каталог данных Antigravity Tools (и уметь открыть его одним кликом)</li><li>Понимать, какие файлы нужно резервировать, а какие — это журналы/кэш</li><li>При устранении неполадок быстро находить журналы и базу данных мониторинга</li><li>Понимать разницу между «закрытием окна» и «выходом из программы» (фоновый режим в трее)</li><li>Различать два типа автозапуска: автозапуск при включении компьютера vs автозапуск прокси</li></ul><h2 id="текущие-проблемы" tabindex="-1">Текущие проблемы <a class="header-anchor" href="#текущие-проблемы" aria-label="Permalink to &quot;Текущие проблемы&quot;">​</a></h2><ul><li>Вы хотите создать резервную копию/мигрировать аккаунты, но не знаете, где они хранятся</li><li>В интерфейсе возникает ошибка/неудача вызова прокси, но вы не можете найти журналы</li><li>Вы закрыли окно и думаете, что программа вышла, но она продолжает работать в фоновом режиме</li></ul><h2 id="когда-использовать-этот-метод" tabindex="-1">Когда использовать этот метод <a class="header-anchor" href="#когда-использовать-этот-метод" aria-label="Permalink to &quot;Когда использовать этот метод&quot;">​</a></h2><ul><li>Вы только что установили Antigravity Tools и хотите подтвердить «где хранятся данные»</li><li>Вы готовитесь сменить компьютер/переустановить систему и хотите сначала создать резервную копию аккаунтов и статистики</li><li>Вам нужно устранить неполадки: сбой OAuth, сбой обновления квоты, сбой запуска прокси, ошибки 401/429 при вызове</li></ul><h2 id="🎒-подготовка" tabindex="-1">🎒 Подготовка <a class="header-anchor" href="#🎒-подготовка" aria-label="Permalink to &quot;🎒 Подготовка&quot;">​</a></h2><ul><li>Установлен и запущен Antigravity Tools</li><li>Вы можете войти на страницу Settings (в правом верхнем углу или на боковой панели)</li><li>Ваш системный аккаунт имеет права доступа к домашнему каталогу</li></ul><div class="warning custom-block"><p class="custom-block-title">Напоминание</p><p>Этот урок расскажет, какие файлы являются «реальными данными», но не рекомендуется редактировать их вручную. Для изменения конфигурации используйте интерфейс.</p></div><h2 id="основная-идея" tabindex="-1">Основная идея <a class="header-anchor" href="#основная-идея" aria-label="Permalink to &quot;Основная идея&quot;">​</a></h2><p>Запомните одно утверждение:</p><p>«<strong>Каталог данных — это единственный источник правды о локальном состоянии; журналы — это первый вход для устранения неполадок.</strong>»</p><p>Antigravity Tools создаст каталог данных <code>.antigravity_tools</code> в вашем домашнем каталоге и поместит туда аккаунты, журналы, базу статистики и другое содержимое (если каталог не существует, он будет создан автоматически).</p><p>В то же время по умолчанию включён трей: при закрытии окна программа не выйдет сразу, а скроется в трей и продолжит работать в фоновом режиме.</p><h2 id="пошаговое-руководство" tabindex="-1">Пошаговое руководство <a class="header-anchor" href="#пошаговое-руководство" aria-label="Permalink to &quot;Пошаговое руководство&quot;">​</a></h2><h3 id="шаг-1-откроите-каталог-данных-на-странице-настроек" tabindex="-1">Шаг 1: Откройте каталог данных на странице настроек <a class="header-anchor" href="#шаг-1-откроите-каталог-данных-на-странице-настроек" aria-label="Permalink to &quot;Шаг 1: Откройте каталог данных на странице настроек&quot;">​</a></h3><p><strong>Зачем</strong> Сначала точно определите каталог данных — это даст вам точку отсчёта для последующего резервного копирования или устранения неполадок.</p><p>Откройте Settings в Antigravity Tools, затем перейдите на вкладку Advanced.</p><p>Вы увидите поле ввода «Каталог данных» (только для чтения, оно покажет реальный путь) и рядом кнопку «Открыть».</p><p>Нажмите кнопку «Открыть».</p><p><strong>Что вы должны увидеть</strong>: Откроется системный файловый менеджер с каталогом, путь похож на <code>~/.antigravity_tools/</code>.</p><h3 id="шаг-2-подтвердите-путь-к-каталогу-данных-кроссплатформенность" tabindex="-1">Шаг 2: Подтвердите путь к каталогу данных (кроссплатформенность) <a class="header-anchor" href="#шаг-2-подтвердите-путь-к-каталогу-данных-кроссплатформенность" aria-label="Permalink to &quot;Шаг 2: Подтвердите путь к каталогу данных (кроссплатформенность)&quot;">​</a></h3><p><strong>Зачем</strong> При написании скриптов для резервного копирования или устранении неполадок в командной строке нужно знать фактический путь этого каталога в вашей системе.</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-v7YJ1" id="tab-mYX5Bng" checked><label data-title="macOS/Linux" for="tab-mYX5Bng">macOS/Linux</label><input type="radio" name="group-v7YJ1" id="tab-SNnq4tX"><label data-title="Windows" for="tab-SNnq4tX">Windows</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.antigravity_tools&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -la</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.antigravity_tools&quot;</span></span></code></pre></div><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$dataDir </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Join-Path</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> $HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;.antigravity_tools&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$dataDir</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Get-ChildItem</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Force $dataDir</span></span></code></pre></div></div></div><p><strong>Что вы должны увидеть</strong>: Каталог существует (если вы впервые открываете страницу настроек, каталог будет создан автоматически).</p><h3 id="шаг-3-узнаите-«ключевые-фаилы»-в-каталоге-данных" tabindex="-1">Шаг 3: Узнайте «ключевые файлы» в каталоге данных <a class="header-anchor" href="#шаг-3-узнаите-«ключевые-фаилы»-в-каталоге-данных" aria-label="Permalink to &quot;Шаг 3: Узнайте «ключевые файлы» в каталоге данных&quot;">​</a></h3><p><strong>Зачем</strong> Не все файлы стоят резервировать. Сначала разберитесь, что такое «данные аккаунтов», а что — «база статистики/журналы».</p><p>Ниже приведены имена файлов из исходного кода проекта, они фиксированные:</p><table tabindex="0"><thead><tr><th>Что вы увидите</th><th>Назначение</th><th>Что важно для вас</th></tr></thead><tbody><tr><td><code>accounts.json</code></td><td>Индекс аккаунтов (список аккаунтов/текущий аккаунт)</td><td>При миграции аккаунтов рекомендуется создавать резервную копию вместе</td></tr><tr><td><code>accounts/</code></td><td>Для каждого аккаунта отдельный файл <code>*.json</code></td><td>Это основные данные аккаунтов</td></tr><tr><td><code>logs/</code></td><td>Каталог журналов приложения</td><td>При устранении неполадок в первую очередь смотрите сюда</td></tr><tr><td><code>token_stats.db</code></td><td>База данных SQLite для Token Stats</td><td>Данные, которые вы видите на странице Token Stats, берутся отсюда</td></tr><tr><td><code>proxy_logs.db</code></td><td>База данных SQLite для Proxy Monitor</td><td>Журналы запросов, которые вы видите на странице Monitor, берутся отсюда</td></tr><tr><td><code>warmup_history.json</code></td><td>Локальная история для Smart Warmup</td><td>В основном используется для избежания повторного warmup</td></tr><tr><td><code>update_settings.json</code></td><td>Настройки обновления (автоматическая проверка/интервал и т.д.)</td><td>Обычно не нужно редактировать вручную</td></tr></tbody></table><p><strong>Что вы должны увидеть</strong>: Как минимум есть каталог <code>logs/</code>; если вы ещё не добавили аккаунты, <code>accounts.json</code>/<code>accounts/</code> могут не появиться.</p><h3 id="шаг-4-запомните-расположение-журналов-для-устранения-неполадок" tabindex="-1">Шаг 4: Запомните расположение журналов (для устранения неполадок) <a class="header-anchor" href="#шаг-4-запомните-расположение-журналов-для-устранения-неполадок" aria-label="Permalink to &quot;Шаг 4: Запомните расположение журналов (для устранения неполадок)&quot;">​</a></h3><p><strong>Зачем</strong> Сообщения об ошибках в интерфейсе обычно показывают только «симптомы», а настоящие причины (например, неудачный запрос, ошибка чтения/записи файла) часто находятся в журналах.</p><p>Antigravity Tools записывает журналы в подкаталог <code>logs/</code> каталога данных.</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-xRejL" id="tab-4dwc0tS" checked><label data-title="macOS/Linux" for="tab-4dwc0tS">macOS/Linux</label><input type="radio" name="group-xRejL" id="tab-C8G5WJk"><label data-title="Windows" for="tab-C8G5WJk">Windows</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -la</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.antigravity_tools/logs&quot;</span></span></code></pre></div><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Get-ChildItem</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Force (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Join-Path</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> $HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;.antigravity_tools\\logs&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div></div></div><p><strong>Что вы должны увидеть</strong>: В каталоге есть файлы журналов с ежедневной ротацией (имя файла начинается с <code>app.log</code>).</p><h3 id="шаг-5-при-необходимости-«очистить-журналы»-используите-функцию-очистки-на-странице-настроек" tabindex="-1">Шаг 5: При необходимости «очистить журналы» используйте функцию очистки на странице настроек <a class="header-anchor" href="#шаг-5-при-необходимости-«очистить-журналы»-используите-функцию-очистки-на-странице-настроек" aria-label="Permalink to &quot;Шаг 5: При необходимости «очистить журналы» используйте функцию очистки на странице настроек&quot;">​</a></h3><p><strong>Зачем</strong> Для некоторых проблем вы хотите воспроизвести её один раз и оставить только этот журнал; сначала очистка журналов упростит сравнение.</p><p>На странице Settings -&gt; Advanced найдите область журналов и нажмите «Очистить журналы».</p><p><strong>Что вы должны увидеть</strong>: Появится диалоговое окно с подтверждением; после подтверждения появится сообщение об успешной очистке.</p><div class="tip custom-block"><p class="custom-block-title">Две вещи, которые вас могут беспокоить</p><ul><li>Журналы автоматически «ротируются по дням» и при запуске пытаются очистить старые журналы старше 7 дней.</li><li>«Очистка журналов» усекает файлы журналов до 0 байт, чтобы запущенные процессы могли продолжать писать в тот же дескриптор файла.</li></ul></div><h3 id="шаг-6-разберитесь-в-разнице-между-«закрытием-окна»-и-«выходом-из-программы»-треи" tabindex="-1">Шаг 6: Разберитесь в разнице между «закрытием окна» и «выходом из программы» (трей) <a class="header-anchor" href="#шаг-6-разберитесь-в-разнице-между-«закрытием-окна»-и-«выходом-из-программы»-треи" aria-label="Permalink to &quot;Шаг 6: Разберитесь в разнице между «закрытием окна» и «выходом из программы» (трей)&quot;">​</a></h3><p><strong>Зачем</strong> По умолчанию в Antigravity Tools включён трей; при нажатии кнопки закрытия в правом верхнем углу окна программа скроется в трей и продолжит работать. Если вы думаете, что она вышла, легко создать ложное впечатление «порт всё ещё занят/программа работает в фоне».</p><p>Вы можете использовать этот небольшой процесс для подтверждения:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Действие: закрыть окно (не выходить)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  Шаг 1                Шаг 2                                  │</span></span>
<span class="line"><span>│  Нажмите закрытие  →   Найдите значок в системном трее/меню  │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Что вы должны увидеть: значок трея всё ещё существует, нажатие на него снова покажет окно.</span></span></code></pre></div><p>В меню трея есть два часто используемых действия (очень удобно, когда не используете интерфейс):</p><ul><li>Переключить аккаунт: переключиться на следующий аккаунт</li><li>Обновить квоту: обновить квоту текущего аккаунта (и одновременно уведомить фронтенд об обновлении отображения)</li></ul><h3 id="шаг-7-настроите-автозапуск-при-включении-чтобы-программа-запускалась-свернутои" tabindex="-1">Шаг 7: Настройте автозапуск при включении (чтобы программа запускалась свёрнутой) <a class="header-anchor" href="#шаг-7-настроите-автозапуск-при-включении-чтобы-программа-запускалась-свернутои" aria-label="Permalink to &quot;Шаг 7: Настройте автозапуск при включении (чтобы программа запускалась свёрнутой)&quot;">​</a></h3><p><strong>Зачем</strong> Если вы хотите, чтобы она работала как «фоновая служба» (трей + фоновое обновление), автозапуск избавит от необходимости вручную открывать её каждый раз.</p><p>На странице Settings -&gt; General найдите «Автозапуск при включении», выберите включить.</p><p><strong>Что вы должны увидеть</strong>: После переключения появится сообщение об успешном включении; при следующем запуске компьютера она будет запущена с параметром <code>--minimized</code>.</p><div class="info custom-block"><p class="custom-block-title">Два типа «автозапуска», не путайте</p><table tabindex="0"><thead><tr><th>Название</th><th>Что означает</th><th>Доказательство</th></tr></thead><tbody><tr><td>Автозапуск при включении</td><td>Автоматический запуск Antigravity Tools при включении компьютера (само приложение)</td><td>Параметры запуска включают <code>--minimized</code>, предоставляется команда <code>toggle_auto_launch</code></td></tr><tr><td>Автозапуск прокси</td><td>После запуска Antigravity Tools, если настроено <code>proxy.auto_start=true</code>, автоматически запускается локальная служба прокси</td><td>При запуске приложения читается конфигурация и <code>start_proxy_service(...)</code></td></tr></tbody></table></div><h2 id="контрольные-точки-✅" tabindex="-1">Контрольные точки ✅ <a class="header-anchor" href="#контрольные-точки-✅" aria-label="Permalink to &quot;Контрольные точки ✅&quot;">​</a></h2><ul><li>[ ] Вы можете видеть реальный путь к каталогу данных на странице Settings -&gt; Advanced</li><li>[ ] Вы можете открыть каталог данных и примерно распознать <code>accounts.json</code>, <code>accounts/</code>, <code>logs/</code>, <code>token_stats.db</code>, <code>proxy_logs.db</code></li><li>[ ] Вы знаете, что журналы находятся в <code>logs/</code>, и умеете быстро просматривать их в командной строке</li><li>[ ] Вы знаете, что после закрытия окна программа остаётся в трее, для выхода нужно использовать Quit в меню трея</li><li>[ ] Вы можете различать «автозапуск при включении» и «автозапуск прокси»</li></ul><h2 id="частые-ошибки" tabindex="-1">Частые ошибки <a class="header-anchor" href="#частые-ошибки" aria-label="Permalink to &quot;Частые ошибки&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Ситуация</th><th>Что вы можете сделать (❌)</th><th>Рекомендуемый подход (✓)</th></tr></thead><tbody><tr><td>Не можете найти каталог данных</td><td>Хаотично искать каталог установки приложения в системе</td><td>Перейдите на Settings -&gt; Advanced, посмотрите «Каталог данных» и откройте одним кликом</td></tr><tr><td>Закрыли окно и думаете, что вышли</td><td>После закрытия окна сразу меняете конфигурацию/порт</td><td>Сначала проверьте, есть ли значок трея; для выхода используйте Quit в трее</td></tr><tr><td>Слишком много журналов, трудно устранять неполадки</td><td>При воспроизведении проблемы просматриваете старые журналы</td><td>Сначала «очистите журналы», затем воспроизведите снова, в конце смотрите только этот файл журнала</td></tr><tr><td>Хотите изменить данные аккаунтов</td><td>Вручную редактировать <code>accounts/*.json</code></td><td>Используйте процессы импорта/экспорта/миграции в интерфейсе (связанные главы следующего раздела объяснят)</td></tr></tbody></table><h2 id="итог-урока" tabindex="-1">Итог урока <a class="header-anchor" href="#итог-урока" aria-label="Permalink to &quot;Итог урока&quot;">​</a></h2><ul><li>Каталог данных фиксирован в <code>.antigravity_tools</code> в домашнем каталоге (в macOS/Linux обычно表现为 скрытый каталог), аккаунты/журналы/база статистики всё здесь</li><li>Каталог журналов — это <code>logs/</code>, при устранении неполадок смотрите в первую очередь; при необходимости можно очистить одним кликом на странице настроек</li><li>Закрытие окна скроет его в трей и продолжит работать; для полного выхода используйте Quit в трее</li><li>Два типа автозапуска: автозапуск при включении (приложение) и автозапуск прокси (Proxy)</li></ul><hr><h2 id="предпросмотр-следующего-урока" tabindex="-1">Предпросмотр следующего урока <a class="header-anchor" href="#предпросмотр-следующего-урока" aria-label="Permalink to &quot;Предпросмотр следующего урока&quot;">​</a></h2><blockquote><p>В следующем уроке мы изучим <strong><a href="./../add-account/">Добавление аккаунтов: OAuth/Refresh Token двойной канал и лучшие практики</a></strong>.</p><p>Вы узнаете:</p><ul><li>Когда использовать OAuth, когда напрямую refresh_token</li><li>Как обрабатывать сбой обратного вызова и когда не удаётся получить refresh_token</li><li>Как массово импортировать refresh_token для быстрого создания пула аккаунтов</li></ul></blockquote><hr><h2 id="приложение-справочник-по-исходному-коду" tabindex="-1">Приложение: Справочник по исходному коду <a class="header-anchor" href="#приложение-справочник-по-исходному-коду" aria-label="Permalink to &quot;Приложение: Справочник по исходному коду&quot;">​</a></h2><details><summary><strong>Нажмите, чтобы раскрыть расположение исходного кода</strong></summary><blockquote><p>Обновлено: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Функция</th><th>Путь к файлу</th><th>Строки</th></tr></thead><tbody><tr><td>Расположение каталога данных (<code>~/.antigravity_tools</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/account.rs#L16-L33" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/account.rs</code></a></td><td>16-33</td></tr><tr><td>Индекс аккаунтов и каталог файлов аккаунтов (<code>accounts.json</code> / <code>accounts/</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/account.rs#L16-L46" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/account.rs</code></a></td><td>16-46</td></tr><tr><td>Каталог журналов и ежедневная ротация (<code>logs/</code> + <code>app.log</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/logger.rs#L17-L83" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/logger.rs</code></a></td><td>17-83</td></tr><tr><td>Очистка журналов (усечение файла)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/logger.rs#L149-L169" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/logger.rs</code></a></td><td>149-169</td></tr><tr><td>Отображение каталога данных на странице настроек + открытие одним кликом</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L525-L576" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>525-576</td></tr><tr><td>Очистка журналов одним кликом на странице настроек (кнопка + логика диалога)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L127-L135" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>127-135</td></tr><tr><td>Очистка журналов одним кликом на странице настроек (кнопка на вкладке Advanced)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L732-L747" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>732-747</td></tr><tr><td>Меню трея и события клика (переключение аккаунтов/обновление/отображение/выход)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/tray.rs#L9-L158" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/tray.rs</code></a></td><td>9-158</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Переключатель автозапуска при включении (<code>toggle_auto_launch</code> / <code>is_auto_launch_enabled</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/autostart.rs#L4-L39" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/autostart.rs</code></a></td><td>4-39</td></tr><tr><td>Команды: открыть каталог данных / получить путь / очистить журналы</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L578-L621" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>578-621</td></tr><tr><td>Имя файла базы данных Token Stats (<code>token_stats.db</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/token_stats.rs#L58-L61" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/token_stats.rs</code></a></td><td>58-61</td></tr><tr><td>Имя файла базы данных Proxy Monitor (<code>proxy_logs.db</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/proxy_db.rs#L5-L8" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/proxy_db.rs</code></a></td><td>5-8</td></tr><tr><td>Имя файла истории Warmup (<code>warmup_history.json</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/scheduler.rs#L14-L17" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/scheduler.rs</code></a></td><td>14-17</td></tr><tr><td>Имя файла настроек обновления (<code>update_settings.json</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/update_checker.rs#L150-L177" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/update_checker.rs</code></a></td><td>150-177</td></tr><tr><td>Автозапуск прокси (запуск службы при <code>proxy.auto_start=true</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/lib.rs#L107-L126" target="_blank" rel="noreferrer"><code>src-tauri/src/lib.rs</code></a></td><td>107-126</td></tr></tbody></table></details>`,67)])])}const u=a(i,[["render",d]]);export{g as __pageData,u as default};
